mapper.sql:
WHERE c.company_id = #{companyId}

  AND (
      c.category_name LIKE CONCAT('%', #{keyword}, '%')
      OR c.description LIKE CONCAT('%', #{keyword}, '%')
  )

mapper.select:
SELECT COUNT(*)
FROM tb_pc_part
WHERE company_id = #{companyId}
  AND category_id = #{categoryId}

mapper.delete:
DELETE FROM tb_part_spec_value
WHERE company_id = #{companyId}
  AND spec_definition_id IN (
    SELECT spec_definition_id
    FROM tb_part_spec_definition
    WHERE company_id = #{companyId}
      AND category_id = #{categoryId}
  )

DELETE FROM tb_part_spec_option
WHERE spec_definition_id IN (
    SELECT spec_definition_id
    FROM tb_part_spec_definition
    WHERE company_id = #{companyId}
      AND category_id = #{categoryId}
)

DELETE FROM tb_part_spec_definition
WHERE company_id = #{companyId}
  AND category_id = #{categoryId}

DELETE FROM tb_part_category
WHERE company_id = #{companyId}
  AND category_id = #{categoryId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_part_category
    WHERE company_id = #{companyId}
      AND category_name = #{categoryName}

        AND category_id <> #{excludeCategoryId}

)
